SELECT COUNT(DISTINCT S.PK_SIAPE) FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON C.SIAPE = S.PK_SIAPE WHERE ((LOWER(C.AREA_INGRESSO) LIKE LOWER('%educacao%') OR LOWER(C.AREA_INGRESSO) LIKE LOWER('%educacao%')) AND (LOWER(C.AREA_INGRESSO) LIKE LOWER('%fisica%') OR LOWER(C.AREA_INGRESSO) LIKE LOWER('%fisica%'))) AND LOWER(S.CONTRATO) = LOWER('efetivos') AND UPPER(C.SIGLA_CAMPUS) = 'VAL' AND C.ANO = 2024 AND C.SEMESTRE = 1